import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './SalesInventory.css';

const SalesInventory = () => {
    const [salesData, setSalesData] = useState({
        product: '',
        date: '',
        quantity: 0,
        staff: '',
        warehouse: '',
        batchNo: '',
        expiry: '',
    });
    const [message, setMessage] = useState('');
    const [loading, setLoading] = useState(false);
    const [products, setProducts] = useState([]);
    const [warehouses, setWarehouses] = useState([]);
    const navigate = useNavigate();

    useEffect(() => {
        const fetchProducts = async () => {
            try {
                const response = await fetch('http://localhost:8000/api/v1/inventory/products');
                if (!response.ok) {
                    throw new Error(`HTTP error! status: ${response.status}`);
                }
                const data = await response.json();
                console.log('Fetched products:', data); // Debugging log
                if (Array.isArray(data)) {
                    setProducts(data);
                } else {
                    console.error('API did not return an array:', data);
                    setProducts([]); // Fallback to an empty array
                }
            } catch (error) {
                console.error('Error fetching products:', error);
                setProducts([]); // Fallback to an empty array
            }
        };

        const fetchWarehouses = async () => {
            try {
                const response = await fetch('http://localhost:8000/api/v1/warehouses');
                if (!response.ok) {
                    throw new Error(`HTTP error! status: ${response.status}`);
                }
                const data = await response.json();
                console.log('Fetched warehouses:', data); // Debugging log
                if (Array.isArray(data)) {
                    setWarehouses(data);
                } else {
                    console.error('API did not return an array:', data);
                    setWarehouses([]); // Fallback to an empty array
                }
            } catch (error) {
                console.error('Error fetching warehouses:', error);
                setWarehouses([]); // Fallback to an empty array
            }
        };

        fetchProducts();
        fetchWarehouses();
    }, []);

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setSalesData({ ...salesData, [name]: value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setMessage('');
        try {
            const response = await fetch('http://localhost:8000/api/v1/sales-inventory', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(salesData),
            });
            const data = await response.json();
            if (response.ok) {
                setMessage('Sales inventory recorded successfully!');
                setSalesData({
                    product: '',
                    date: '',
                    quantity: 0,
                    staff: '',
                    warehouse: '',
                    batchNo: '',
                    expiry: '',
                });
            } else {
                setMessage('Failed to record sales inventory.');
            }
        } catch (error) {
            setMessage('An error occurred. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="sales-inventory-container">
            <h1>Sales Inventory</h1>
            <div className="sales-inventory-buttons">
                <button onClick={() => navigate('/product-stock-intake')}>Product Stock Intake</button>
                <button onClick={() => { console.log('Navigating to /product-stock-level'); navigate('/product-stock-level'); }}>Product Stock Level</button>
                <button onClick={() => navigate('/generate-invoice')}>Generate Invoice</button>
                <button onClick={() => navigate('/sales-summary')}>Sales Summary</button>
                <button onClick={() => navigate('/customer-performance')}>Customer Performance</button>
            </div>
            <form onSubmit={handleSubmit} className="sales-inventory-form">
                <label>
                    Product:
                    <select
                        name="product"
                        value={salesData.product}
                        onChange={handleInputChange}
                        required
                    >
                        <option value="">Select a product</option>
                        {products.map((product) => (
                            <option key={product.id} value={product.id}>
                                {product.name}
                            </option>
                        ))}
                    </select>
                </label>
                <label>
                    Date:
                    <input
                        type="date"
                        name="date"
                        value={salesData.date}
                        onChange={handleInputChange}
                        required
                    />
                </label>
                <label>
                    Quantity:
                    <input
                        type="number"
                        name="quantity"
                        value={salesData.quantity}
                        onChange={handleInputChange}
                        required
                    />
                </label>
                <label>
                    Staff:
                    <input
                        type="text"
                        name="staff"
                        value={salesData.staff}
                        onChange={handleInputChange}
                        required
                    />
                </label>
                <label>
                    Warehouse:
                    <select
                        name="warehouse"
                        value={salesData.warehouse}
                        onChange={handleInputChange}
                        required
                    >
                        <option value="">Select a warehouse</option>
                        {warehouses.map((warehouse) => (
                            <option key={warehouse.id} value={warehouse.id}>
                                {warehouse.name}
                            </option>
                        ))}
                    </select>
                </label>
                <label>
                    Batch No.:
                    <input
                        type="text"
                        name="batchNo"
                        value={salesData.batchNo}
                        onChange={handleInputChange}
                    />
                </label>
                <label>
                    Expiry Date:
                    <input
                        type="date"
                        name="expiry"
                        value={salesData.expiry}
                        onChange={handleInputChange}
                    />
                </label>
                <button type="submit" disabled={loading}>{loading ? 'Submitting...' : 'Submit'}</button>
            </form>
            {message && <div className={message.includes('success') ? 'success' : 'error'} style={{marginTop:'1rem'}}>{message}</div>}
        </div>
    );
};

export default SalesInventory;
